VALUES
  ('heelevel3-53250add-moex-00002', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-b6671682', 'sub-heelevel3-53250add-01', NULL, 'essay', '甲公司在相關市場占有率達到四分之一，目前持有乙公司10%已發行股
份，打算透過公開收購再取得該公司 22%股份，達到總持股32%之水準。
甲公司並且規劃公開收購完成後，在下次股東常會取得乙公司 7席董事
中之 4席，再推選其中一人擔任董事長。查乙公司為上市公司，各年度
出席股東會的股份總數通常僅占已發行股份總數的 51%至55%，歷年來
都未曾超過 58%。請問本件公開收購應否事先向公平交易委員會提出申
報？在申報時應以何者為申報人？（15 分）
23540', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "2b521a03614d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0917", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公平交易法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00003', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-b6671682', 'sub-heelevel3-53250add-01', NULL, 'essay', '甲為 3C 行動裝置網路達人，經常在大型社交平台個人網頁公開分享手
機、平板電腦、智慧手錶、智慧手環、智慧眼鏡等攜帶式電子裝置的規
格功能、特性分析、使用經驗與優缺點比較。這些貼文的網路流傳度與
閱讀率都不低，經常被同樣喜好行動裝置的讀者們閱讀、參考與轉貼。
乙公司為跨國性智慧手錶品牌，為進入國內市場，以10 萬元為代價委託
甲發表該公司新款智慧手錶的購買試用經驗，即一般所謂的開箱文。然
而乙公司並未實際提供該款產品供甲試用，反而直接模仿甲的貼文風格
撰寫開箱文，在缺乏親身使用經驗之情形下，由甲透過其帳號在各大社
交平台發表貼文，且未透露與乙公司間的報酬關係。消費者丙閱讀之後，
發現該款產品在國內尚未正式上市，懷疑甲並無實際使用經驗，向公平
交易委員會提出檢舉。請附具理由，分別說明甲與乙公司上述行為是否
違反公平交易法之規定。（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "2b521a03614d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0917", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公平交易法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00004', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'essay', '甲因家中冰箱故障至乙商場選購新冰箱，當場展示之具有自動製冰功能
的冰箱甚符合甲之心意，經詢問賣場工作人員，得知該型號目前缺貨中，
要 1 個月後才會到貨。甲心急如焚，遂詢問可否將展示品 A 冰箱帶回
家。甲認為 A冰箱在現場冰箱門已經經多人開合，門把上多處留有使用
痕跡，雖不影響使用但和全新品仍有差距，遂商請乙予以折扣。工作人
員表示，可以賣給甲，但因為 A冰箱只是展示並未被實際插電試用，只
願意折價新臺幣500 元。最後甲因為家中沒有冰箱確實不便，遂同意以
折價新臺幣 500元之價格購入 A冰箱，並當場載回家。詎料，回家使用
後，第 2天便發現 A冰箱除了製冰盒無法如同廣告宣稱的自動製冰外，
其他功能一切正常，但甲之所以屬意 A冰箱，就是因為其有自動製冰功
能，夏天隨時可以在飲料中加冰塊。於是甲便主張因 A有瑕疵要退貨，
要求乙換一台同型號的全新冰箱給甲。試附理由說明，甲的主張是否有
理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00005', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'essay', '甲租用乙所有的 A 地建築房屋，於租賃關係存續中，乙將 A 地出賣予
丙，買賣契約（以下稱系爭契約）中約定，「雙方同意，若丙方以本契約
標的申請銀行貸款，核貸結果未能達本契約約定價金之 7 成，則合約無
效」。甲得知後，主張有優先承買權，乙表示系爭契約係約定丙能順利取
得貸款，作為生效條件，為附條件之買賣契約；丙是否能順利取得貸款
乃將來客觀不確定事實，甲無從主張優先承買權。試附理由說明，甲可
否主張優先承買權？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00006', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲與乙為同一棟社區之住戶，甲住8樓，乙住7樓，甲生性愛熱鬧，常常邀約親朋好友到家作客， 並大聲喧嘩，甚至已半夜時分仍在家中高歌作樂。下列敘述，何者錯誤？', '["在他人居住區域，發出超越一般人社會生活所能忍受之噪音，屬不法侵害他人居住安寧之人格 利益", "人格利益至高無上，不容侵犯，只要遭受侵害，不問程度如何，被害人均得依民法第195條第 1項有關人格及身分法益侵害規定，請求賠償相當之金額", "如果長期、持續性噪音，已使人因此無法入眠，健康受損，可能構成健康權之侵害", "健康權屬於特別人格權，若受侵害，被害人得請求非財產上之金錢賠償 23520"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00007', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲將A地出賣於乙，並辦理所有權移轉登記。下列關於所有權移轉之敘述，何者錯誤？', '["應以書面為之", "非經登記，不生效力", "非經移轉占有，不生效力", "此移轉行為係法律行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00008', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '父親甲贈與未成年子女乙一棟房屋，由甲代理乙受領，其效力如何？', '["無效", "有效", "效力未定", "得撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00009', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '民法中關於權利主體「自然人」之規定，下列敘述，何者正確？', '["某藝人以「小香瓜」為藝名，因其非真名，不受民法有關姓名權規定之保護", "甲與乙同時遇難，不能證明死亡先後時，視為同時死亡", "丙因失蹤多時生死不明，被妻子依法聲請法院宣告其死亡。但丙實則仍生存中，卻因已受死亡 宣告，所以權利能力及行為能力均為消滅", "丁開車闖紅燈撞上正在過馬路之孕婦戊，致其胎兒受傷。戊為胎兒之法定代理人，固得代為受 領丁給付之賠償金，但若嗣後胎兒死產，該受領之賠償金應返還丁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00010', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲依民法規定發起設立A學術性社團法人，並將其主事務所設於臺中市。依民法規定，A法人應 向何主管機關登記，始得成立？', '["臺中市政府", "臺中地方法院", "內政部", "教育部"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00011', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲80歲，罹輕度失智症，配偶已歿，有子女乙、丙、丁，平日由女兒乙照顧，乙擔心甲因心智缺 陷，而面臨不必要之法律糾紛，遂向法院聲請為甲為輔助宣告，法院經審查對甲為輔助宣告，並 以乙為甲之輔助人。下列甲之行為，何者須先取得輔助人乙之同意？', '["甲與好友相約到餐廳吃飯", "甲在好友A、B偕同下到C公證人處，在A、B、C見證下自書遺囑，就其法定繼承人乙、丙、 丁為遺產分配各得1/2、1/4、1/4", "甲因開車造成D受傷，自行與D成立和解契約，願意理賠D之身體傷害新臺幣（下同）50萬元", "甲自行到某百貨公司購買價錢1萬元之手錶"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL)
